from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

SECRET_KEY = 'your-secret-key'  # Replace with your actual secret key

@app.route('/api/gateway', methods=['POST'])
def api_gateway():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return jsonify({'error': 'Authorization header missing'}), 401

    token = auth_header.split(" ")[1]
    try:
        # Decode the JWT token without verification for development
        decoded_token = jwt.decode(token, SECRET_KEY, algorithms=["HS256"])
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

    # Extract user claims
    user_claims = decoded_token.get('user_claims', {})

    # Forward request to backend service (mocked here)
    response = forward_to_backend(user_claims)
    return jsonify(response)

def forward_to_backend(user_claims):
    # Mock function to represent forwarding to backend service
    return {'status': 'success', 'user_claims': user_claims}

